using namespace std;
struct segTree {
  int l, r;
  long long sum;
  long long tag;
  segTree *ls, *rs;
  segTree(int _l, int _r) {
    l = _l, r = _r;
    ls = rs = nullptr;
    sum = tag = 0;
  }
  inline void update(long long val) {
    tag += val;
    sum += val;
  }
  void pushDown() {
    if (ls == nullptr) {
      int m = l + r >> 1;
      ls = new segTree(l, m);
      rs = new segTree(m, r);
    }
    if (tag) {
      ls->update(tag);
      rs->update(tag);
      tag = 0;
    }
  }
  void pushUp() { sum = min(ls->sum, rs->sum); }
  void update(int L, int R, long long val) {
    if (L <= l and R >= r) {
      update(val);
    } else if (R <= l or r <= L) {
      return;
    } else {
      pushDown();
      ls->update(L, R, val);
      rs->update(L, R, val);
      pushUp();
    }
  }
  long long query(int L, int R) {
    if (L <= l and R >= r) {
      return sum;
    } else if (R <= l or r <= L) {
      return 1e18;
    } else {
      pushDown();
      return min(ls->query(L, R), rs->query(L, R));
    }
  }
  void init() {
    if (r - l == 1) {
      sum = 0;
    } else {
      pushDown();
      ls->init();
      rs->init();
      pushUp();
    }
  }
};
struct seg {
  long long c;
  int l, r;
  bool operator<(const seg &s) const { return c < s.c; }
};
int main() {
  int n, m;
  cin >> n >> m;
  vector<seg> s(n);
  for (int i = 0; i < n; i++) {
    cin >> s[i].l >> s[i].r >> s[i].c;
  }
  segTree cover(1, m);
  sort(s.begin(), s.end());
  long long ans = 1e18;
  int r = 0;
  for (int i = 0; i < s.size(); i++) {
    while (!cover.query(1, m)) {
      if (r >= n) {
        cout << ans;
        return 0;
      }
      cover.update(s[r].l, s[r].r, 1);
      r++;
    }
    ans = min(ans, s[r - 1].c - s[i].c);
    cover.update(s[i].l, s[i].r, -1);
  }
  cout << ans;
  return 0;
}

