void turn(ptr o) {
  ptr s = o->p, t = s->p;
  if (!root(s)) (s == t->i ? t->i : t->j) = o;
  s->p = o, o->p = t;
  if (o == s->i)
    s->i = o->j, o->j->p = s, o->j = s->up();
  else
    s->j = o->i, o->i->p = s, o->i = s->up();
