#include <bits/stdc++.h>
using namespace std;
const int MAXQ = 5e4;
const int MAXN = 50;
int n, q;
int m, par[MAXQ * MAXN + 10], w[MAXQ * MAXN + 10], curBlockIdx;
bool isBlock[MAXQ * MAXN + 10];
vector<int> adj[MAXQ * MAXN + 10];
vector<pair<long long, long long> > blockRanges;
char s[10];
enum QueryType {
  ASK,
  BLOCK,
};
struct Query {
  QueryType queryType;
  long long u, v;
  vector<int> vertexIdx;
  int res;
};
Query queries[MAXQ];
struct Vertex {
  pair<long long, long long> range;
  int idx;
  Vertex() {}
  Vertex(const pair<long long, long long>& range, const int& idx)
      : range(range), idx(idx) {}
  bool operator<(const Vertex& other) const {
    return this->range < other.range;
  }
};
struct Node {
  list<Vertex> vertices;
  Node *lef, *rig;
  Node() : lef(NULL), rig(NULL) {}
};
Node* root = NULL;
void insert(const long long& u, const long long& v, Node*& node = root,
            const long long& lef = 0, const long long& rig = (1LL << n) - 1) {
  if (node == NULL) node = new Node;
  if (u == lef && v == rig) {
    node->vertices.push_back(Vertex(pair<long long, long long>(lef, rig), ++m));
    if (curBlockIdx != -1) {
      isBlock[m] = true;
      queries[curBlockIdx].vertexIdx.push_back(m);
    }
    return;
  }
  long long mid = (lef + rig) >> 1;
  if (v <= mid)
    insert(u, v, node->lef, lef, mid);
  else if (u > mid)
    insert(u, v, node->rig, mid + 1, rig);
  else {
    insert(u, mid, node->lef, lef, mid);
    insert(mid + 1, v, node->rig, mid + 1, rig);
  }
}
void merge(Node*& node, const long long& len) {
  list<Vertex>::iterator iterU = node->lef->vertices.begin(),
                         iterV = node->rig->vertices.begin(), iterUU, iterVV;
  do {
    iterUU = iterU, iterVV = iterV;
    adj[iterU->idx].push_back(iterV->idx);
    adj[iterV->idx].push_back(iterU->idx);
    if (iterU->range.second + len <= iterV->range.second) ++iterUU;
    if (iterV->range.second <= iterU->range.second + len) ++iterVV;
    iterU = iterUU, iterV = iterVV;
  } while (iterU != node->lef->vertices.end() ||
           iterV != node->rig->vertices.end());
  node->vertices.swap(node->lef->vertices);
  node->vertices.splice(node->vertices.end(), node->rig->vertices);
}
void init(Node*& node = root, const long long& lef = 0,
          const long long& rig = (1LL << n) - 1) {
  if (!node->vertices.empty()) return;
  long long mid = (lef + rig) >> 1;
  init(node->lef, lef, mid);
  init(node->rig, mid + 1, rig);
  merge(node, mid - lef + 1);
}
int findRoot(const int& u) {
  if (u == par[u]) return u;
  return par[u] = findRoot(par[u]);
}
void join(int u, int v) {
  if (isBlock[u] || isBlock[v]) return;
  u = findRoot(u), v = findRoot(v);
  if (u == v) return;
  if (w[u] < w[v]) swap(u, v);
  par[v] = u;
  w[u] += v;
}
int main() {
  scanf("%d %d", &n, &q);
  for (int idx = 0; idx < q; ++idx) {
    scanf("%s %lld %lld", s, &queries[idx].u, &queries[idx].v);
    if (strcmp(s, "ask") == 0)
      queries[idx].queryType = QueryType::ASK;
    else {
      queries[idx].queryType = QueryType::BLOCK;
      curBlockIdx = idx;
      blockRanges.push_back(
          pair<long long, long long>(queries[idx].u, queries[idx].v));
      insert(queries[idx].u, queries[idx].v);
    }
  }
  curBlockIdx = -1;
  sort(blockRanges.begin(), blockRanges.end());
  if (blockRanges[0].first > 0) insert(0, blockRanges[0].first - 1);
  for (int idx = 0; idx < blockRanges.size(); ++idx) {
    if (idx + 1 < blockRanges.size()) {
      if (blockRanges[idx].second + 1 < blockRanges[idx + 1].first)
        insert(blockRanges[idx].second + 1, blockRanges[idx + 1].first - 1);
    } else {
      if (blockRanges[idx].second + 1 < (1LL << n))
        insert(blockRanges[idx].second + 1, (1LL << n) - 1);
    }
  }
  init();
  for (int i = 1; i <= m; ++i) {
    par[i] = i;
    w[i] = 1;
  }
  for (int u = 1; u <= m; ++u)
    for (const int& v : adj[u]) join(u, v);
  vector<Vertex> rootVertices(root->vertices.begin(), root->vertices.end());
  for (int idx = q - 1; idx >= 0; --idx)
    if (queries[idx].queryType == QueryType::ASK) {
      vector<Vertex>::iterator iter = upper_bound(
          rootVertices.begin(), rootVertices.end(),
          Vertex(pair<long long, long long>(queries[idx].u, 1LL << n), m + 1));
      --iter;
      int u = iter->idx;
      iter = upper_bound(
          rootVertices.begin(), rootVertices.end(),
          Vertex(pair<long long, long long>(queries[idx].v, 1LL << n), m + 1));
      --iter;
      int v = iter->idx;
      queries[idx].res = (findRoot(u) == findRoot(v) ? 1 : 0);
    } else {
      for (const int& u : queries[idx].vertexIdx) {
        isBlock[u] = false;
        for (const int& v : adj[u]) join(u, v);
      }
    }
  for (int idx = 0; idx < q; ++idx)
    if (queries[idx].queryType == QueryType::ASK)
      printf("%d\n", queries[idx].res);
  return 0;
}

#include <bits/stdc++.h>
using namespace std;
const int _MAX = 1e+9 + 7;
int _pow(int n, int __pow, vector<int>* _mem = nullptr) {
  int res = 1;
  if (_mem != nullptr) _mem->emplace_back(res);
  while (__pow--) {
    res = ((long long)res * n) % _MAX;
    if (_mem != nullptr) _mem->emplace_back(res);
  }
  return res;
}
int solve(int n, int k) {
  if (!k) return 1;
  int _f = _pow(2, n - 1), _g = _pow(2, n) - 1;
  if (n % 2) return _pow(((long long)_f + 1) % _MAX, k);
  _f--;
  vector<int> _f_mem, _g_mem;
  int res = _pow(_f, k, &_f_mem);
  _pow((1 + (long long)_g) % _MAX, k - 1, &_g_mem);
  for (int i = 0; i <= k - 1; i++)
    res = ((((long long)_f_mem[i] * _g_mem[k - 1 - i]) % _MAX) + res) % _MAX;
  return res;
}
int main() {
  int t;
  cin >> t;
  while (t--) {
    int n, k;
    cin >> n >> k;
    cout << solve(n, k) << endl;
  }
}

