struct Treap {
  Treap *l, *r;
  long long pri;
  pair<long long, long long> seg;
  long long tag;
  Treap(long long _L, long long _R)
      : l(nullptr), r(nullptr), pri(rand()), seg(make_pair(_L, _R)), tag(0) {}
};
Treap *treap = nullptr;
long long treap_sz;
void push(Treap *&T) {
  if (T == nullptr) return;
  T->seg.first += T->tag;
  T->seg.second += T->tag;
  if (T->l != nullptr) T->l->tag += T->tag;
  if (T->r != nullptr) T->r->tag += T->tag;
  T->tag = 0;
}
Treap *Merge(Treap *a, Treap *b) {
  if (a == nullptr) return b;
  if (b == nullptr) return a;
  if (a->pri < b->pri) {
    push(a);
    a->r = Merge(a->r, b);
    return a;
  } else {
    push(b);
    b->l = Merge(a, b->l);
    return b;
  }
}
void Split_by_L(Treap *T, Treap *&a, Treap *&b, long long k) {
  if (T == nullptr) {
    a = b = nullptr;
    return;
  }
  push(T);
  if (T->seg.first <= k) {
    a = T;
    Split_by_L(a->r, a->r, b, k);
  } else {
    b = T;
    Split_by_L(b->l, a, b->l, k);
  }
}
Treap *&Last(Treap *&T) {
  if (T == nullptr) return T;
  push(T);
  if (T->r == nullptr) return T;
  return Last(T->r);
}
void Insertion_sort(Treap *&T, long long pos) {
  if (pos == 1) {
    T->tag += 1;
    T = Merge(new Treap(1, 1), T);
    treap_sz += 1;
    return;
  }
  Treap *a, *b, *c;
  Split_by_L(T, a, b, pos - 1);
  Treap *&Node = Last(a);
  if (Node->seg.second > pos - 1) {
    c = new Treap(pos + 1, Node->seg.second + 1);
    treap_sz += 1;
    Node->seg.second = pos;
  } else {
    c = nullptr;
    Node->seg.second = pos;
  }
  if (b != nullptr) b->tag += 1;
  T = Merge(Merge(a, c), b);
}
