void solve() {
  cin >> n >> s;
  suff_array fo(s, '$');
  fo.get_st();
  vector<long long> dp(n, 0);
  int z;
  long long ans = 0;
  for (int i = 0; i < n; i++) {
    dp[i] = n - i;
    for (int j = 0; j < i; j++) {
      if (fo.c[j] > fo.c[i]) continue;
      z = fo.Lcp(i, j);
      dp[i] = max(dp[i], dp[j] + n - z - i);
    }
    ans = max(ans, dp[i]);
  }
  cout << ans << '\n';
}
