  Node(pair<int, pair<int, int>> v, int p)
      : p(p), size(1), v(v), L(nullptr), R(nullptr) {}
  Node(Node* h) { *this = *h; }
  Node* update() {
    size = 1;
    if (L) size += L->size;
    if (R) size += R->size;
