}
mt19937 rnd;
struct Treap {
  Node *root, *L, *M, *R;
  Treap(int seed = 0) : root(nullptr) { rnd.seed(seed); }
  virtual void split(Node* p, pair<int, pair<int, int>> v, Node*& L, Node*& R) {
    if (not p) return L = R = nullptr, void();
    if (p->v <= v)
      L = p, split(p->R, v, p->R, R);
    else
      R = p, split(p->L, v, L, p->L);
    p->update();
  }
  virtual Node* merge(Node* L, Node* R) {
    if (not L) return R;
    if (not R) return L;
    if (L->p < R->p) return L->R = merge(L->R, R), L->update();
    return R->L = merge(L, R->L), R->update();
  }
  Node* insert(Node* p, pair<int, pair<int, int>> v) {
    split(p, v, L, R);
    return merge(merge(L, new Node(v, rand())), R);
  }
  void insert(pair<int, pair<int, int>> v) { root = insert(root, v); }
  Node* remove(Node* p, pair<int, pair<int, int>> v) {
    split(p, v, L, R);
    split(L, mus(v), L, M);
    return merge(merge(L, M ? merge(M->L, M->R) : M), R);
  }
  void remove(pair<int, pair<int, int>> v) { root = remove(root, v); }
  int rank(Node* p, pair<int, pair<int, int>> v) {
    if (not p) return 1;
    if (p->v >= v) return rank(p->L, v);
    return 1 + p->Lsize() + rank(p->R, v);
  }
  int rank(pair<int, pair<int, int>> v) { return rank(root, v); }
  Node* kth(Node* p, int k) {
    if (not p or k > p->size) return nullptr;
    if (k <= p->Lsize()) return kth(p->L, k);
    if (k == p->Lsize() + 1) return p;
    return kth(p->R, k - p->Lsize() - 1);
  }
  Node* kth(int k) { return kth(root, k); }
  Node* pedecessor(Node* p, pair<int, pair<int, int>> v) {
    if (not p) return p;
    if (p->v >= v) return pedecessor(p->L, v);
    R = pedecessor(p->R, v);
    return R ? R : p;
  }
  Node* pedecessor(pair<int, pair<int, int>> v) { return pedecessor(root, v); }
  Node* successor(Node* p, pair<int, pair<int, int>> v) {
    if (not p) return p;
    if (p->v <= v) return successor(p->R, v);
    L = successor(p->L, v);
    return L ? L : p;
  }
  Node* successor(pair<int, pair<int, int>> v) { return successor(root, v); }
  int size() { return root->size; }
