  if (T[u].size() >= 3) {
    ans = min(ans, (long long)T[u].kth(1)->v.first + T[u].kth(2)->v.first +
                       T[u].kth(3)->v.first);
  }
  if (T[v].size() >= 3) {
    ans = min(ans, (long long)T[v].kth(1)->v.first + T[v].kth(2)->v.first +
                       T[v].kth(3)->v.first);
  }
  if (T[u].size() >= 2 && T[v].size() >= 2) {
    pair<int, pair<int, int>> fw = T[u].kth(2)->v, fx = T[v].kth(2)->v;
    if (fw.second.second == fx.second.second) {
      if (T[u].size() >= 3) {
        ans = min(ans, (long long)T[u].kth(3)->v.first + fx.first);
      }
      if (T[v].size() >= 3) {
        ans = min(ans, (long long)fw.first + T[v].kth(3)->v.first);
      }
    } else
      ans = min(ans, (long long)fw.first + fx.first);
  }
  {
    int l = 0, r = ALL.size() + 1;
    while (l + 1 < r) {
      int mid = (l + r) / 2;
      pair<int, pair<int, int>> ky =
          make_pair(ALL.kth(mid)->v.first, make_pair(mod, mod));
      int cnt =
          (ALL.rank(ky) - 1) - (T[u].rank(ky) - 1) - (T[v].rank(ky) - 1) + 1;
      if (cnt > 0)
        r = mid;
      else
        l = mid;
    }
    if (r <= ALL.size())
      ans = min(ans, (long long)mi.first + ALL.kth(r)->v.first);
  }
  return ans;
}
