  ios_base::sync_with_stdio(false);
  cin.tie(NULL);
  bool mt = 1;
  int tests = 1;
  if (mt) cin >> tests;
  for (int tt = 1; tt <= tests; ++tt) {
    solver();
  }
  return 0;
}

