template <class T>
class BlockAllocator {
 private:
  static const long long BlockL = 10000;
  union TItem {
    char rt[sizeof(T)];
    TItem *next;
  };
  TItem *pool, *tail;
  TItem *unused;

 public:
  BlockAllocator() {
    pool = NULL;
    unused = NULL;
  }
  T *allocate() {
    TItem *p;
    if (unused) {
      p = unused;
      unused = unused->next;
    } else {
      if (pool == NULL) pool = new TItem[BlockL], tail = pool;
      p = tail++;
      if (tail == pool + BlockL) pool = NULL;
    }
    return (T *)p;
  }
  void deallocate(T *pt) {
    TItem *p = (TItem *)pt;
    p->next = unused, unused = p;
  }
};
struct edgeWeight;
struct path_message;
struct lcc_circle;
