const int mxn = 2e3 + 5;
struct Hull {
  int x[mxn], y[mxn], sz;
  Hull() { sz = 0; }
  void push_back(int X, int Y) {
    while (sz >= 2 && 1LL * (y[sz - 1] - Y) * (x[sz - 2] - x[sz - 1]) <
                          1LL * (y[sz - 2] - y[sz - 1]) * (x[sz - 1] - X))
      --sz;
    x[sz] = X, y[sz] = Y, ++sz;
  }
};
Hull conv(Hull a, Hull b) {
  int bx = a.x[0] + b.x[0], by = a.y[0] + b.y[0];
  Hull c;
  c.push_back(bx, by);
  for (int i = 1, j = 1; i < a.sz || j < b.sz;) {
    if (i < a.sz && (j == b.sz ||
                     1LL * (a.y[i - 1] - a.y[i]) * (b.x[j - 1] - b.x[j]) <
                         1LL * (b.y[j - 1] - b.y[j]) * (a.x[i - 1] - a.x[i]))) {
      c.push_back(bx += a.x[i] - a.x[i - 1], by += a.y[i] - a.y[i - 1]);
      ++i;
    } else {
      c.push_back(bx += b.x[j] - b.x[j - 1], by += b.y[j] - b.y[j - 1]);
      ++j;
    }
  }
  return c;
}
i64 query(Hull a, int x) {
  int lb = 0, rb = a.sz - 1;
  while (lb < rb) {
    int md = (lb + rb) >> 1;
    if (a.y[md] - a.y[md + 1] < 1LL * x * (a.x[md] - a.x[md + 1]))
      lb = md + 1;
    else
      rb = md;
  }
  return a.y[lb] - 1LL * a.x[lb] * x;
}
