namespace SOL {
struct Node {
  int dx, dy, sx, sy;
  size_t siz;
  Node *ch[2], *fa;
  Node(int _dx, int _dy) {
    dx = sx = _dx, dy = sy = _dy;
    siz = 1;
    ch[0] = ch[1] = fa = nullptr;
  }
  ~Node() {
    if (ch[0]) delete ch[0];
    if (ch[1]) delete ch[1];
  }
};
using node = Node *;
inline bool comp(node a, node b) {
  return 1LL * a->dy * b->dx < 1LL * b->dy * a->dx;
}
inline void pushup(node x) {
  x->sx = x->dx, x->sy = x->dy, x->siz = 1;
  if (x->ch[0])
    x->sx += x->ch[0]->sx, x->sy += x->ch[0]->sy, x->siz += x->ch[0]->siz;
  if (x->ch[1])
    x->sx += x->ch[1]->sx, x->sy += x->ch[1]->sy, x->siz += x->ch[1]->siz;
}
inline void rotate(node x) {
  node y = x->fa, z = y->fa;
  if (z) z->ch[y == z->ch[1]] = x;
  x->fa = z;
  bool d = x == y->ch[1];
  y->ch[d] = x->ch[d ^ 1];
  if (y->ch[d]) y->ch[d]->fa = y;
  x->ch[d ^ 1] = y;
  y->fa = x;
  pushup(y);
  pushup(x);
}
inline node splay(node x) {
  while (x->fa) {
    node y = x->fa, z = y->fa;
    if (z) rotate((x == y->ch[1]) ^ (y == z->ch[1]) ? x : y);
    rotate(x);
  }
  return x;
}
inline node __insert(node x, node v) {
  if (!x) return v;
  if (comp(x, v))
    x->ch[1] = __insert(x->ch[1], v), x->ch[1]->fa = x;
  else
    x->ch[0] = __insert(x->ch[0], v), x->ch[0]->fa = x;
  pushup(x);
  return x;
}
inline node insert(node x, node v) {
  __insert(x, v);
  return splay(v);
}
inline node merge(node x, node y) {
  if (!x || !y) return x ? x : y;
  if (x->siz < y->siz) std::swap(x, y);
  node ls = y->ch[0], rs = y->ch[1];
  y->ch[0] = y->ch[1] = y->fa = nullptr;
  x = merge(x, ls);
  x = insert(x, y);
  x = merge(x, rs);
  return x;
}
inline void debug(node x) {
