long long int fast_pow(long long int a, long long int p, long long int m) {
  long long int res = 1;
  while (p) {
    if (p % 2 == 0) {
      a = (a * a) % m;
      p /= 2;
    } else {
      res = (res * a) % m;
      p--;
    }
  }
