class FenwickTree {
 private:
  vector<long long> bit;
  long long n;

 public:
  FenwickTree(long long n) {
    this->n = n;
    bit.assign(n, 0);
  }
  FenwickTree(vector<long long> &a) : FenwickTree(a.size()) {
    for (long long i = 0; i < a.size(); i++) {
      add(i, a[i]);
    }
  }
  long long sum(long long r) {
    long long res = 0;
    for (; r >= 0; r = (r & (r + 1)) - 1) {
      res += bit[r];
    }
    return res;
  }
  void add(long long idx, long long delta) {
    for (; idx < n; idx = idx | (idx + 1)) {
      bit[idx] += delta;
    }
  }
  friend vector<long long> tree(const FenwickTree &f1) { return f1.bit; }
};
class Segtree {
 public:
  vector<long long> tree;
  long long n;
  Segtree(long long n) {
    this->n = n;
    tree.assign(2 * n, 0);
  }
  Segtree(vector<long long> &a) : Segtree(a.size()) {
    for (long long i = 0; i < a.size(); i++) {
      add(i, a[i]);
    }
  }
  void add(long long k, long long delta) {
    k += n;
    tree[k] += delta;
    for (k /= 2; k >= 1; k /= 2) {
      tree[k] = tree[2 * k] + tree[2 * k + 1];
    }
  }
  long long sum(long long a, long long b) {
    a += n;
    b += n;
    long long res = 0;
    while (a <= b) {
      if (a % 2 == 1) {
        res += tree[a++];
      }
      if (b % 2 == 0) {
        res += tree[b--];
      }
      b /= 2;
      a /= 2;
    }
    return res;
  }
};
