const int N = 5010;
int n, k;
char s[N];
int C[N][N];
int sum[N];
int top;
pii stk[N];
void main() {
  in(n, k);
  if (k == 0) {
    out(1);
    return;
  }
  scanf("%s", s + 1);
  int ans = 0;
  for (int i = (0); i <= (n); ++i) {
    C[i][0] = 1;
    for (int j = (1); j <= (i); ++j)
      C[i][j] = add(C[i - 1][j - 1], C[i - 1][j]);
  }
  for (int i = (1); i <= (n); ++i) sum[i] = sum[i - 1] + (s[i] == '1');
  for (int i = 1, j = 1; i <= n; ++i) {
    if (s[i - 1] == '0') continue;
    while (j + 1 <= n && sum[j + 1] - sum[i - 1] <= k) ++j;
    if (sum[j] - sum[i - 1] != k) break;
    stk[++top] = {i, j};
  }
  if (!top) {
    out(1);
    return;
  }
  for (int i = (1); i <= (top - 1); ++i) {
    ans = add(ans, C[stk[i][1] - stk[i][0] + 1][k]);
    if (stk[i][1] >= stk[i + 1][0]) {
      ans = sub(ans, C[stk[i][1] - stk[i + 1][0] + 1]
                      [sum[stk[i][1]] - sum[stk[i + 1][0] - 1]]);
    } else
      ans = sub(ans, 1);
  }
  ans = add(ans, C[stk[top][1] - stk[top][0] + 1][k]);
  out(ans);
}
